def get_args_view():
    url = pp_url()[0]
    resp_text = requests.get(url).text
    obj = re.compile('<input type="hidden" name="__VIEWSTATE" id="__VIEWSTATE" value="(?P<vie>.*?)" />', re.S)
    args_view = re.search(obj, resp_text).group('vie')
    return args_view


def qty_hr1(em: int, shift: str) -> float:
    """
    获取总工时函数
    :param em: 人数
    :param shift: 班别
    :return: 工时
    """
    if shift == 'D':
        # 初始化开始时间
        past_time = datetime.now().replace(hour=8, minute=0, second=0, microsecond=0)
        # 获取当前时间
        current_time = datetime.now()
        if int(str(current_time).split(' ')[1][0:2]) > 19:  # 大于19:00每人减掉0.66H
            # 计算时间差（以小时为单位，向下取整） 时差乘以人力整除3600秒计算总工时
            qty_hr = round((current_time - past_time).total_seconds() * em // 3600) - em * 0.66
        elif int(str(current_time).split(' ')[1][0:2]) > 16:  # 大于16:00每人减掉1.66H
            qty_hr = round((current_time - past_time).total_seconds() * em // 3600) - em * 1.66
        elif int(str(current_time).split(' ')[1][0:2]) >= 12:  # 大于12:00每人减掉1H
            qty_hr = round((current_time - past_time).total_seconds() * em // 3600) - em * 1
        else:
            qty_hr = round((current_time - past_time).total_seconds() * em // 3600)
            if qty_hr == 0:
                return 1
    else:
        # 初始化开始时间
        past_time = datetime.now().replace(hour=20, minute=0, second=0, microsecond=0)
        # 获取当前时间
        current_time = datetime.now()
        if round((current_time - past_time).total_seconds()) < 0:
            if int(str(current_time).split(' ')[1][0:2]) > 7:  # 大于7:00每人减掉0.66H
                # 计算时间差（以小时为单位，向下取整） 时差乘以人力整除3600秒计算总工时
                qty_hr = (round((current_time - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 0.66
            elif int(str(current_time).split(' ')[1][0:2]) > 5:  # 到达05:00每人减掉1.66H
                qty_hr = (round((current_time - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 1.66
            elif int(str(current_time).split(' ')[1][0:2]) >= 1:  # 到达01:00每人减掉1H
                qty_hr = (round((current_time - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 1
            else:
                qty_hr = (round((current_time - past_time).total_seconds() + 24 * 3600) * em // 3600)
        else:
            qty_hr = round((current_time - past_time).total_seconds() * em // 3600)
            if qty_hr == 0:
                return 1
    return qty_hr


def upph(sub_em: int, tnb_em: int, shift: str) -> dict:
    """
    获取实际的UPPH
    :param shift: 班别
    :param tnb_em: TNB人力
    :param sub_em:SUB人力
    :return: 产量，工时，UPPH
    """
    qty_hr_sub = qty_hr1(sub_em, shift)
    qty_hr_tnb = qty_hr1(tnb_em, shift)
    # print(f'当前SUB总工时为：{qty_hr_sub}')
    # print(f'当前TNB总工时为：{qty_hr_tnb}')
    try:
        qty = qcm(shift)
        upph_sub = round(qty['SUB'] / qty_hr_sub, 2)
        upph_tnb = round(qty['K3FA31TNB'] / qty_hr_tnb, 2)
        if upph:
            # print(f'当前SUB_UPPH为：{sub_upph}')
            data = {
                'product_qty_sub': qty['SUB'],
                'qty_hr_sub': round(qty_hr_sub, 2),
                'upph_sub': upph_sub,
                'product_qty_tnb': qty['K3FA31TNB'],
                'qty_hr_tnb': round(qty_hr_tnb, 2),
                'upph_tnb': upph_tnb,
                'qty_data_list': qty['data']
            }
            # print(f'{line}:', data)
            return {"code": 0, "data": data}
        else:
            # 这里是错误的
            data = {
                'product_qty_sub': qty['SUB'],
                'qty_hr_sub': round(qty_hr_sub, 2),
                'upph_sub': upph_sub,
                'product_qty_tnb': qty['K3FA31TNB'],
                'qty_hr_tnb': round(qty_hr_tnb, 2),
                'upph_tnb': upph_tnb,
                'qty_data_list': qty['data']
            }
            return {"code": 1, "data": data}
    except Exception as e:
        return {"code": 1, "error": f"数据出错,加速修复中。。。 {e}"}


